using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;
using ShipmentTracker.Data.Entities;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        // Dispatcher: list all shipments
        group.MapGet("/", [Authorize] async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    ActualDelivery = s.ActualDelivery,
                    RecipientName = s.RecipientName,
                    SenderName = s.SenderName,
                    WeightKg = s.WeightKg,
                    Notes = s.Notes
                })
                .ToListAsync();
            return Results.Ok(shipments);
        });

        // Dispatcher: update shipment status
        group.MapPut("/{id:int}/status", [Authorize] async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.Include(s => s.Events).FirstOrDefaultAsync(s => s.Id == id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.NewStatus;
            shipment.Notes = request.Notes ?? shipment.Notes;

            if (request.NewStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            shipment.Events.Add(new ShipmentEvent
            {
                Timestamp = DateTime.UtcNow,
                Description = $"Status changed to {request.NewStatus}",
                Location = shipment.Destination
            });

            await db.SaveChangesAsync();
            return Results.Ok();
        });

        // Customer: track by tracking number (no auth required)
        app.MapGet("/api/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Include(s => s.Events)
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null) return Results.NotFound();

            var result = new TrackingResult
            {
                TrackingNumber = shipment.TrackingNumber,
                Status = shipment.Status,
                Destination = shipment.Destination,
                EstimatedDelivery = shipment.EstimatedDelivery,
                ActualDelivery = shipment.ActualDelivery,
                RecipientName = shipment.RecipientName,
                Events = shipment.Events
                    .OrderByDescending(e => e.Timestamp)
                    .Select(e => new TrackingEvent
                    {
                        Timestamp = e.Timestamp,
                        Description = e.Description,
                        Location = e.Location
                    })
                    .ToList()
            };

            return Results.Ok(result);
        });
    }
}

