@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by tracking #, destination, or recipient..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Status Filter:</label>
        <select class="form-select" style="width: auto; display: inline-block;" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>

    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Recipient</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Weight (kg)</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><strong>@shipment.TrackingNumber</strong></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.RecipientName</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>@shipment.WeightKg</td>
                    <td>
                        @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                        {
                            <button class="btn btn-sm btn-primary" @onclick="() => ShowUpdateDialog(shipment)">
                                Update
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@if (selectedShipment is not null)
{
    <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Update @selectedShipment.TrackingNumber</h5>
                    <button type="button" class="btn-close" @onclick="CloseDialog"></button>
                </div>
                <div class="modal-body">
                    <div class="mb-3">
                        <label class="form-label">New Status</label>
                        <select class="form-select" @bind="newStatus">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Notes</label>
                        <textarea class="form-control" @bind="updateNotes" rows="3"></textarea>
                    </div>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CloseDialog">Cancel</button>
                    <button type="button" class="btn btn-primary" @onclick="UpdateStatus" disabled="@isUpdating">
                        @if (isUpdating) { <span>Saving...</span> } else { <span>Save</span> }
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private ShipmentDto? selectedShipment;
    private ShipmentStatus newStatus;
    private string? updateNotes;
    private bool isUpdating;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
        {
            if (!string.IsNullOrEmpty(statusFilter) && s.Status.ToString() != statusFilter)
                return false;
            if (!string.IsNullOrEmpty(filterText))
            {
                var filter = filterText.ToLowerInvariant();
                return s.TrackingNumber.Contains(filter, StringComparison.OrdinalIgnoreCase)
                    || s.Destination.Contains(filter, StringComparison.OrdinalIgnoreCase)
                    || s.RecipientName.Contains(filter, StringComparison.OrdinalIgnoreCase);
            }
            return true;
        }) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private void ShowUpdateDialog(ShipmentDto shipment)
    {
        selectedShipment = shipment;
        newStatus = shipment.Status;
        updateNotes = shipment.Notes;
    }

    private void CloseDialog() => selectedShipment = null;

    private async Task UpdateStatus()
    {
        if (selectedShipment is null) return;
        isUpdating = true;

        var request = new UpdateShipmentStatusRequest { NewStatus = newStatus, Notes = updateNotes };
        var response = await Http.PutAsJsonAsync($"/api/shipments/{selectedShipment.Id}/status", request);

        if (response.IsSuccessStatusCode)
        {
            selectedShipment.Status = newStatus;
            selectedShipment.Notes = updateNotes;
            if (newStatus == ShipmentStatus.Delivered)
                selectedShipment.ActualDelivery = DateTime.UtcNow;
        }

        isUpdating = false;
        CloseDialog();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/"
@page "/track"
@using ShipmentTracker.Client.Models
@inject HttpClient Http

<PageTitle>Track Your Shipment</PageTitle>

<div class="container">
    <div class="row justify-content-center mt-4">
        <div class="col-md-8">
            <h1 class="text-center mb-4">📦 Track Your Shipment</h1>

            <div class="card shadow-sm">
                <div class="card-body">
                    <div class="input-group input-group-lg">
                        <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-2026-001)"
                               @bind="trackingNumber" @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                            @if (isLoading) { <span>Searching...</span> } else { <span>Track</span> }
                        </button>
                    </div>
                </div>
            </div>

            @if (errorMessage is not null)
            {
                <div class="alert alert-warning mt-3">@errorMessage</div>
            }

            @if (result is not null)
            {
                <div class="card mt-4 shadow-sm">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <h5 class="mb-0">@result.TrackingNumber</h5>
                        <span class="badge @GetStatusBadgeClass(result.Status) fs-6">@result.Status</span>
                    </div>
                    <div class="card-body">
                        <div class="row mb-3">
                            <div class="col-md-6">
                                <strong>Recipient:</strong> @result.RecipientName
                            </div>
                            <div class="col-md-6">
                                <strong>Destination:</strong> @result.Destination
                            </div>
                        </div>
                        <div class="row mb-3">
                            <div class="col-md-6">
                                <strong>Estimated Delivery:</strong>
                                @(result.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")
                            </div>
                            <div class="col-md-6">
                                @if (result.ActualDelivery is not null)
                                {
                                    <strong>Delivered On:</strong> @result.ActualDelivery.Value.ToString("MMM dd, yyyy HH:mm")
                                }
                            </div>
                        </div>

                        @if (result.Events.Any())
                        {
                            <h6 class="mt-4">Tracking History</h6>
                            <div class="list-group">
                                @foreach (var evt in result.Events)
                                {
                                    <div class="list-group-item">
                                        <div class="d-flex justify-content-between">
                                            <strong>@evt.Description</strong>
                                            <small class="text-muted">@evt.Timestamp.ToString("MMM dd, HH:mm")</small>
                                        </div>
                                        <small class="text-muted">📍 @evt.Location</small>
                                    </div>
                                }
                            </div>
                        }
                    </div>
                </div>
            }
        </div>
    </div>
</div>

@code {
    private string trackingNumber = "";
    private TrackingResult? result;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        result = null;

        try
        {
            var response = await Http.GetAsync($"/api/track/{trackingNumber.Trim()}");
            if (response.IsSuccessStatusCode)
            {
                result = await response.Content.ReadFromJsonAsync<TrackingResult>();
            }
            else
            {
                errorMessage = "Shipment not found. Please check your tracking number and try again.";
            }
        }
        catch
        {
            errorMessage = "An error occurred while tracking. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

