toolArgs.file_text:
@page "/"
@page "/track"
@using ShipmentTracker.Client.Models
@inject HttpClient Http

<PageTitle>Track Your Shipment</PageTitle>

<div class="container">
    <div class="row justify-content-center mt-4">
        <div class="col-md-8">
            <h1 class="text-center mb-4">📦 Track Your Shipment</h1>

            <div class="card shadow-sm">
                <div class="card-body">
                    <div class="input-group input-group-lg">
                        <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-2026-001)"
                               @bind="trackingNumber" @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                            @if (isLoading) { <span>Searching...</span> } else { <span>Track</span> }
                        </button>
                    </div>
                </div>
            </div>

            @if (errorMessage is not null)
            {
                <div class="alert alert-warning mt-3">@errorMessage</div>
            }

            @if (result is not null)
            {
                <div class="card mt-4 shadow-sm">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <h5 class="mb-0">@result.TrackingNumber</h5>
                        <span class="badge @GetStatusBadgeClass(result.Status) fs-6">@result.Status</span>
                    </div>
                    <div class="card-body">
                        <div class="row mb-3">
                            <div class="col-md-6">
                                <strong>Recipient:</strong> @result.RecipientName
                            </div>
                            <div class="col-md-6">
                                <strong>Destination:</strong> @result.Destination
                            </div>
                        </div>
                        <div class="row mb-3">
                            <div class="col-md-6">
                                <strong>Estimated Delivery:</strong>
                                @(result.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")
                            </div>
                            <div class="col-md-6">
                                @if (result.ActualDelivery is not null)
                                {
                                    <strong>Delivered On:</strong> @result.ActualDelivery.Value.ToString("MMM dd, yyyy HH:mm")
                                }
                            </div>
                        </div>

                        @if (result.Events.Any())
                        {
                            <h6 class="mt-4">Tracking History</h6>
                            <div class="list-group">
                                @foreach (var evt in result.Events)
                                {
                                    <div class="list-group-item">
                                        <div class="d-flex justify-content-between">
                                            <strong>@evt.Description</strong>
                                            <small class="text-muted">@evt.Timestamp.ToString("MMM dd, HH:mm")</small>
                                        </div>
                                        <small class="text-muted">📍 @evt.Location</small>
                                    </div>
                                }
                            </div>
                        }
                    </div>
                </div>
            }
        </div>
    </div>
</div>

@code {
    private string trackingNumber = "";
    private TrackingResult? result;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        result = null;

        try
        {
            var response = await Http.GetAsync($"/api/track/{trackingNumber.Trim()}");
            if (response.IsSuccessStatusCode)
            {
                result = await response.Content.ReadFromJsonAsync<TrackingResult>();
            }
            else
            {
                errorMessage = "Shipment not found. Please check your tracking number and try again.";
            }
        }
        catch
        {
            errorMessage = "An error occurred while tracking. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

